# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity

class ShareHandlerActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_handler)

        val sharedContentTextView = findViewById<TextView>(R.id.shared_content_text_view)
        handleIntent(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleIntent(intent)
    }

    private fun handleIntent(intent: Intent) {
        if (intent.action == Intent.ACTION_SEND) {
            val type = intent.type
            when {
                "text/plain" == type -> {
                    val text = intent.getStringExtra(Intent.EXTRA_TEXT)
                    sharedContentTextView.text = "Shared Text:\n$text"
                }
                type?.startsWith("image/") == true -> {
                    val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
                    sharedContentTextView.text = "Shared Image: $imageUri"
                }
                else -> {
                    sharedContentTextView.text = "Unknown Content Type"
                }
            }
        } else if (intent.action == Intent.ACTION_SEND_MULTIPLE) {
            val uris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
            sharedContentTextView.text = "Shared Images:\n${uris?.joinToString("\n")}"
        }
    }
}